scwin.f_prefareCheck = async function () {
  for (let i = 0; i < ds_retrieve.getRowCount(); i++) {
    if (ds_retrieve.getCellData(i, 'impExpClsCd') == "I") {
      let rowStatus = ds_retrieve.getRowStatus(i);
      if (rowStatus == "C" || rowStatus == "U") {
        if (!dscommon.cf_CheckCntrNo(ds_retrieve.getCellData(i, 'cntrNo'))) {
          await $c.win.alert($p, "유효한 컨테이너 번호가 아닙니다. 컨테이너 번호를 확인하십시요.");
          return;
        }
      }
    }
    let rowStatus = ds_retrieve.getRowStatus(i);
    if (rowStatus == "U" || rowStatus == "C") {
      if (ds_retrieve.getCellData(i, 'cntrNo') == "") {
        await $c.win.alert($p, "컨테이너 번호를 입력하세요!");
        return false;
      }
      if (ds_retrieve.getCellData(i, 'crryinoutIntendDt') == "") {
        await $c.win.alert($p, "반납일을 입력하세요!");
        return false;
      }
      if (ds_retrieve.getCellData(i, 'crryinoutIntendHh') == "") {
        await $c.win.alert($p, "반납시간을 입력하세요!");
        return false;
      }
      if (ds_retrieve.getCellData(i, "impExpClsCd") == "O") {
        if (ds_retrieve.getCellData(i, 'sealNo') == "") {
          await $c.win.alert($p, "봉인번호를 입력하세요!");
          return false;
        }
      }
      if (ds_retrieve.getCellData(i, 'drvNm') == "") {
        await $c.win.alert($p, "기사명을 입력하세요!");
        return false;
      }
      if (ds_retrieve.getCellData(i, 'drvTelNo') == "") {
        await $c.win.alert($p, "연락처를 입력하세요!");
        return false;
      }
      if (ds_retrieve.getCellData(i, 'vehclNo') == "") {
        await $c.win.alert($p, "차량을 입력하세요!");
        return false;
      }
      if (ds_retrieve.getCellData(i, 'vehclIdCardNo') == "") {
        await $c.win.alert($p, "ID CARD를 입력하세요!");
        return false;
      }
      if (scwin.f_sameYn() && ds_retrieve.getCellData(i, "impExpClsCd") == "I" && ds_retrieve.getCellData(i, "fullEmptyClsCd") == "E" && ds_retrieve.getCellData(i, "wrkPlCd") == "4C02" && ds_retrieve.getCellData(i, "crryinoutClsCd") == "I") {
        if (ds_retrieve.getCellData(i, "crryinoutIntendDt") > ds_retrieve.getCellData(i, "cntrRtrnDt") || $c.gus.cfIsNull($p, ds_retrieve.getCellData(i, "cntrRtrnDt"))) {
          await $c.win.alert($p, "선사에서 반납기한 재지정 받으세요");
          return false;
        }
      }

      //라인코드가 SITC이고, ODR_CTRL_CLS_CD = 3 인경우에 체선일자 체크
      if (ds_retrieve.getCellData(i, "line") == "SITC" && ds_retrieve.getCellData(i, "odrCtrlClsCd") == "3") {
        let sysDate = $c.date.getServerDateTime($p, "yyyyMMdd");
        let demDate = ds_retrieve.getCellData(i, "cntrRtrnDt");
        if (!demDate == "") {
          if (parseInt(demDate) < parseInt(sysDate)) {
            //20090801 < 20090918
            //statFlag = false;
            return false;
          }
        } else {
          await $c.win.alert($p, "반납기한을 지정받으세요.");
          ds_retrieve.setCellData(i, 'vehclNo', "");
          ds_retrieve.setCellData(i, 'drvTelNo', "");
          ds_retrieve.setCellData(i, 'drvNm', "");
          ds_retrieve.setCellData(i, "vehclIdCardNo", "");
          return false;
        }
      }
    }
  }
};

