scwin.f_OzReport = async function () {
  let curRow = ds_retrieve.getRowPosition();
  if (ds_retrieve.getCellData(curRow, "fullEmptyClsCd2") != "E") {
    await $c.win.alert($p, "의왕CY EMPTY 반납인 경우만 하차증 발행 가능합니다.");
    return false;
  }
  let ozrId = "/ds/op/wrkrslts/cywrkrslts/op_301_02_21r_D.ozr";
  let odiId = "op_301_02_21r";

  // 쿼리(ODI)에 적용할 파라미터를 설정(OZParam)
  let checkCount = 0;
  let crryinoutIntendNo = "";
  let printYn = 0;
  let rowCount = ds_retrieve.getRowCount();
  for (let i = 0; i < rowCount; i++) {
    if (ds_retrieve.getCellData(i, "chk") == "1") {
      /*
      if(ds_retrieve.getCellData(i, "crryinoutIntendDt") != scwin.nowDt){
          await $c.win.alert("당일 예약만 하차증 발급이 가능합니다.");
          return;
      }*/

      // 검색어 세팅
      dma_printYnCondition.set("selfTransClntNo", ds_retrieve.getCellData(0, "selfTransCoClntNo"));
      dma_printYnCondition.set("onReqNo", ds_retrieve.getCellData(0, "onReqNo"));
      dma_printYnCondition.set("onReqGoodsSeq", ds_retrieve.getCellData(i, "onReqGoodsSeq"));
      dma_printYnCondition.set("printYn", "1");
      let impExpClsCd = ds_retrieve.getCellData(i, "impExpClsCd");
      dma_printYnCondition.set("impExpClsCd", impExpClsCd == "I" ? "I" : null);
      crryinoutIntendNo = ds_retrieve.getCellData(i, "crryinoutIntendNo");
      dma_printYnCondition.set("crryinoutClsCd", ds_retrieve.getCellData(i, "crryinoutClsCd"));
      let offPrintYnVal = ds_retrieve.getCellData(i, "offPrintYn");
      printYn = parseInt(offPrintYnVal);
    } else {
      checkCount++;
    }
  }

  // 유효성 검사
  if (rowCount == checkCount) {
    await $c.win.alert($p, "하차증을 발행할 컨테이너를 선택하세요.");
    return false;
  }
  if (crryinoutIntendNo == "") {
    await $c.win.alert($p, "선택된 컨테이너는 예정정보를 먼저 등록하신 후에 하차증을 발행할 수 있습니다.");
    return false;
  }
  if (printYn >= 1) {
    await $c.win.alert($p, "선택된 컨테이너는 이미 하차증이 발행되었습니다.\n추가 발행을 원하시면 담당자에게 문의하세요.");
    return false;
  }
  $c.sbm.execute($p, sbm_updatePrintYn);

  // 2. 리포트 호출 데이터 구성
  let data = {
    odiName: odiId,
    reportName: ozrId,
    odiParam: {
      sysPath: "dbl.ds.op.wrkrslts.cywrkrslts",
      crryinoutIntendNo: crryinoutIntendNo
    },
    viewerParam: {
      useprogressbar: false
    },
    formParam: {}
  };
  if (cbx_printCheck.getValue() == "1" && cbx_previewCheck.getValue() == "0") {
    data.viewerParam.mode = "print";
  } else {
    data.viewerParam.mode = "preview";
  }
  await scwin.openPopup(data);
  scwin.f_Retrieve();
};
