/*현재시간조회 0000 현태로 가져온다.*/
scwin.f_getTime = function () {
  scwin.currDate = new Date();
  scwin.currTime = scwin.leadingZeros(scwin.currDate.getHours(), 2) + scwin.leadingZeros(scwin.currDate.getMinutes(), 2);
  scwin.currDay = scwin.currDate.getDay();
  scwin.tempHoliday = scwin.currDate.getFullYear() + scwin.leadingZeros(scwin.currDate.getMonth() + 1, 2) + scwin.leadingZeros(scwin.currDate.getDate(), 2);
};

/**
 * 자릿수 앞자리 0 채우기
 * leadingZeros([num], [자릿수]) 
 * > leadingZeros(12, 3) -> '012'
 */
scwin.leadingZeros = function (n, digits) {
  let zero = '';
  n = n.toString();
  if (n.length < digits) {
    for (let i = 0; i < digits - n.length; i++) {
      zero += '0';
    }
  }
  return zero + n;
};
